import{_ as n,C as i,o as t,c as r,a2 as o,b as d,w as a,a as l,E as c,a3 as m}from"./chunks/framework.B72_uj9U.js";const v=JSON.parse('{"title":"Pi — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/pi-coding-agent/context-management.md","filePath":"research/agents/pi-coding-agent/context-management.md"}'),p={name:"research/agents/pi-coding-agent/context-management.md"};function h(u,e,g,f,b,x){const s=i("Mermaid");return t(),r("div",null,[e[1]||(e[1]=o('<h1 id="pi-—-context-management" tabindex="-1">Pi — Context Management <a class="header-anchor" href="#pi-—-context-management" aria-label="Permalink to &quot;Pi — Context Management&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Pi manages LLM context through a layered system of static files, dynamic injection, progressive disclosure, and automatic compaction. The design reflects Pi&#39;s &quot;primitives not features&quot; philosophy — each layer is simple and independently useful, but they compose into a flexible context management strategy that rivals more complex agents.</p><p>The key innovation is progressive disclosure: rather than front-loading all context into the system prompt (which hurts prompt cache hit rates and wastes tokens), Pi loads capabilities and knowledge on-demand as the conversation requires them.</p><h2 id="static-context-layers" tabindex="-1">Static Context Layers <a class="header-anchor" href="#static-context-layers" aria-label="Permalink to &quot;Static Context Layers&quot;">​</a></h2><h3 id="agents-md-—-project-instructions" tabindex="-1">AGENTS.md — Project Instructions <a class="header-anchor" href="#agents-md-—-project-instructions" aria-label="Permalink to &quot;AGENTS.md — Project Instructions&quot;">​</a></h3><p>AGENTS.md is Pi&#39;s equivalent of Claude Code&#39;s CLAUDE.md or Cursor&#39;s <code>.cursorrules</code>. It&#39;s a Markdown file in the project root that provides project-specific instructions to the agent.</p><p><strong>Loading behavior:</strong></p><ul><li>Loaded at startup before the first user message</li><li>Injected into the system prompt or as an early user message</li><li>Can include coding conventions, project structure, testing requirements, deployment notes</li><li>Supports nested AGENTS.md files in subdirectories for per-module instructions</li></ul><p><strong>Example use cases:</strong></p><ul><li>&quot;This project uses Vitest for testing, not Jest&quot;</li><li>&quot;Always run <code>pnpm lint</code> after editing TypeScript files&quot;</li><li>&quot;The API lives in <code>src/api/</code>, the frontend in <code>src/web/</code>&quot;</li></ul><h3 id="system-md-—-system-prompt-customization" tabindex="-1">SYSTEM.md — System Prompt Customization <a class="header-anchor" href="#system-md-—-system-prompt-customization" aria-label="Permalink to &quot;SYSTEM.md — System Prompt Customization&quot;">​</a></h3><p>SYSTEM.md allows per-project customization of Pi&#39;s system prompt itself. This is more powerful than AGENTS.md — it modifies the instructions the LLM receives about how to behave, not just project context.</p><p><strong>Two modes:</strong></p><ol><li><strong>Append mode</strong> (default): SYSTEM.md content is appended to Pi&#39;s default system prompt</li><li><strong>Replace mode</strong>: SYSTEM.md completely replaces Pi&#39;s default system prompt</li></ol><p><strong>Why this matters</strong>: Most coding agents don&#39;t let you modify the system prompt. Pi&#39;s default system prompt is intentionally minimal, and SYSTEM.md gives users full control over LLM behavior. You can change the agent&#39;s personality, add domain-specific reasoning instructions, or enforce strict coding standards at the system level.</p><h2 id="dynamic-context" tabindex="-1">Dynamic Context <a class="header-anchor" href="#dynamic-context" aria-label="Permalink to &quot;Dynamic Context&quot;">​</a></h2><h3 id="skills-as-progressive-disclosure" tabindex="-1">Skills as Progressive Disclosure <a class="header-anchor" href="#skills-as-progressive-disclosure" aria-label="Permalink to &quot;Skills as Progressive Disclosure&quot;">​</a></h3><p>Skills (SKILL.md files) are Pi&#39;s primary mechanism for progressive context disclosure:</p>',19)),(t(),d(m,null,{default:a(()=>[c(s,{id:"mermaid-99",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20Startup%5B%22Startup%22%5D%0A%20%20%20%20%20%20%20%20S1%5B%22System%20prompt%20(minimal)%3Cbr%2F%3E%2B%20SYSTEM.md%20(append%20or%20replace)%3Cbr%2F%3E%2B%20AGENTS.md%20(project%20instructions)%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20OnDemand%5B%22On%20Demand%22%5D%0A%20%20%20%20%20%20%20%20O1%5B%22Skills%20loaded%20via%20%2Fskill%3Aname%20or%20auto-detection%3Cbr%2F%3E%E2%80%A2%20Database%20migration%20skill%3Cbr%2F%3E%E2%80%A2%20Docker%20deployment%20skill%3Cbr%2F%3E%E2%80%A2%20Testing%20framework%20skill%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20ExtInjected%5B%22Extension-Injected%22%5D%0A%20%20%20%20%20%20%20%20E1%5B%22Dynamic%20messages%20from%20extensions%3Cbr%2F%3E%E2%80%A2%20RAG%20results%20from%20code%20search%3Cbr%2F%3E%E2%80%A2%20Git%20context%20(recent%20commits%2C%20blame%20info)%3Cbr%2F%3E%E2%80%A2%20External%20knowledge%20base%20queries%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Compaction%5B%22Compaction%22%5D%0A%20%20%20%20%20%20%20%20C1%5B%22Older%20messages%20summarized%20to%20free%20space%3Cbr%2F%3ERecent%20messages%20preserved%20in%20full%22%5D%0A%20%20%20%20end%0A%20%20%20%20Startup%20--%3E%20OnDemand%20--%3E%20ExtInjected%20--%3E%20Compaction%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o(`<p><strong>Why progressive disclosure matters for prompt cache</strong>: If all skills were loaded at startup, the system prompt would vary based on which skills exist in the project. This would invalidate the prompt cache for every project. By loading skills on-demand, the system prompt stays stable and cacheable.</p><h3 id="prompt-templates" tabindex="-1">Prompt Templates <a class="header-anchor" href="#prompt-templates" aria-label="Permalink to &quot;Prompt Templates&quot;">​</a></h3><p>Reusable Markdown prompts that can be invoked via <code>/name</code>:</p><ul><li>Stored in <code>~/.pi/agent/prompts/</code> or project directories</li><li>Can include template variables</li><li>Useful for repetitive tasks: <code>/review</code>, <code>/test</code>, <code>/deploy</code></li><li>Distributed via packages</li></ul><h3 id="extension-driven-dynamic-context" tabindex="-1">Extension-Driven Dynamic Context <a class="header-anchor" href="#extension-driven-dynamic-context" aria-label="Permalink to &quot;Extension-Driven Dynamic Context&quot;">​</a></h3><p>Extensions can inject context at multiple points in the conversation:</p><ul><li><strong>Pre-message injection</strong>: Add context before the LLM sees a user message (e.g., inject relevant file contents based on the question)</li><li><strong>History filtering</strong>: Remove or modify messages before they&#39;re sent to the LLM (e.g., strip large tool outputs that are no longer relevant)</li><li><strong>RAG integration</strong>: Query external knowledge bases and inject results as context</li><li><strong>Conditional loading</strong>: Load additional context based on what the agent is doing (e.g., load test framework docs when the agent is writing tests)</li></ul><h2 id="compaction" tabindex="-1">Compaction <a class="header-anchor" href="#compaction" aria-label="Permalink to &quot;Compaction&quot;">​</a></h2><p>Compaction is Pi&#39;s strategy for managing context window limits. When the conversation grows too long, older messages are summarized to free space.</p><h3 id="how-compaction-works" tabindex="-1">How Compaction Works <a class="header-anchor" href="#how-compaction-works" aria-label="Permalink to &quot;How Compaction Works&quot;">​</a></h3><ol><li><strong>Threshold detection</strong>: Pi monitors token count relative to the model&#39;s context window</li><li><strong>Message selection</strong>: Older messages (not the most recent exchanges) are selected for summarization</li><li><strong>Summarization</strong>: Selected messages are sent to the LLM with a summarization prompt</li><li><strong>Replacement</strong>: The original messages are replaced with the summary in the conversation history</li><li><strong>Continuation</strong>: The agent continues with the compacted context</li></ol><h3 id="auto-vs-manual-compaction" tabindex="-1">Auto vs Manual Compaction <a class="header-anchor" href="#auto-vs-manual-compaction" aria-label="Permalink to &quot;Auto vs Manual Compaction&quot;">​</a></h3><ul><li><strong>Auto compaction</strong>: Triggered automatically when approaching the context window limit. The threshold and behavior are configurable.</li><li><strong>Manual compaction</strong>: Users can trigger compaction via commands when they want to start fresh-ish without losing all context.</li></ul><h3 id="extension-customization" tabindex="-1">Extension Customization <a class="header-anchor" href="#extension-customization" aria-label="Permalink to &quot;Extension Customization&quot;">​</a></h3><p>Extensions can fully customize compaction:</p><ul><li>Change the summarization prompt</li><li>Modify the compaction threshold</li><li>Choose which messages are compacted (protect certain messages)</li><li>Replace the entire compaction strategy (e.g., use embeddings instead of summarization)</li><li>Implement &quot;smart compaction&quot; that preserves messages about unresolved tasks</li></ul><h2 id="cross-provider-context-handoff" tabindex="-1">Cross-Provider Context Handoff <a class="header-anchor" href="#cross-provider-context-handoff" aria-label="Permalink to &quot;Cross-Provider Context Handoff&quot;">​</a></h2><p>Pi-ai&#39;s cross-provider context handoff is a unique context management challenge. When switching LLM providers mid-conversation (e.g., from Claude to GPT-4), the conversation history must be translated:</p><h3 id="translation-challenges" tabindex="-1">Translation Challenges <a class="header-anchor" href="#translation-challenges" aria-label="Permalink to &quot;Translation Challenges&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source Feature</th><th>Translation Required</th></tr></thead><tbody><tr><td>Anthropic thinking traces</td><td>Convert to system messages or annotations</td></tr><tr><td>Signed content blobs</td><td>Cannot leave provider — must be replaced with text summaries</td></tr><tr><td>Provider-specific reasoning fields</td><td>Map to the target provider&#39;s format</td></tr><tr><td>Extended thinking content</td><td>Different field names across providers</td></tr><tr><td>Tool call IDs</td><td>Different ID formats and reference patterns</td></tr></tbody></table><h3 id="how-pi-ai-handles-it" tabindex="-1">How Pi-ai Handles It <a class="header-anchor" href="#how-pi-ai-handles-it" aria-label="Permalink to &quot;How Pi-ai Handles It&quot;">​</a></h3><p>Pi-ai converts conversations between provider formats at the API boundary. This is best-effort — some provider-specific features (like signed blobs) can&#39;t be perfectly translated. But the result is that users can switch providers mid-conversation without losing context, which is unique among terminal coding agents.</p><h2 id="tree-structured-sessions" tabindex="-1">Tree-Structured Sessions <a class="header-anchor" href="#tree-structured-sessions" aria-label="Permalink to &quot;Tree-Structured Sessions&quot;">​</a></h2><p>Pi&#39;s session storage is one of its most architecturally interesting features. Sessions are stored as JSONL files where each entry has an <code>id</code> and <code>parentId</code>, forming a tree structure.</p><h3 id="why-trees-instead-of-linear-logs" tabindex="-1">Why Trees Instead of Linear Logs <a class="header-anchor" href="#why-trees-instead-of-linear-logs" aria-label="Permalink to &quot;Why Trees Instead of Linear Logs&quot;">​</a></h3><p>Most coding agents store sessions as linear arrays of messages. Pi&#39;s tree structure enables:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>                    root</span></span>
<span class="line"><span>                   /    \\</span></span>
<span class="line"><span>                msg1    msg1&#39;  (branched from root)</span></span>
<span class="line"><span>                 |       |</span></span>
<span class="line"><span>                msg2    msg2&#39;</span></span>
<span class="line"><span>                / \\</span></span>
<span class="line"><span>           msg3   msg3&#39;  (branched from msg2)</span></span>
<span class="line"><span>            |      |</span></span>
<span class="line"><span>           msg4   msg4&#39;</span></span></code></pre></div><ul><li><strong>In-place branching</strong>: Try a different approach without creating a new session file</li><li><strong>Navigation</strong>: <code>/tree</code> shows the full session tree, jump to any point</li><li><strong>Forking</strong>: <code>/fork</code> creates a new session starting from the current branch point</li><li><strong>History preservation</strong>: All branches are preserved — nothing is ever lost</li><li><strong>Exploration</strong>: Try multiple approaches, compare results, merge the best</li></ul><h3 id="session-commands" tabindex="-1">Session Commands <a class="header-anchor" href="#session-commands" aria-label="Permalink to &quot;Session Commands&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/tree</code></td><td>Display the session tree, navigate to any node</td></tr><tr><td><code>/fork</code></td><td>Create a new session from the current branch</td></tr><tr><td><code>/export</code></td><td>Export session to HTML</td></tr><tr><td><code>/gist</code></td><td>Share session as a GitHub gist</td></tr></tbody></table><h3 id="jsonl-storage-format" tabindex="-1">JSONL Storage Format <a class="header-anchor" href="#jsonl-storage-format" aria-label="Permalink to &quot;JSONL Storage Format&quot;">​</a></h3><p>Each line in the JSONL file is a message with:</p><ul><li><code>id</code>: Unique message identifier</li><li><code>parentId</code>: ID of the parent message (forms the tree)</li><li><code>role</code>: user, assistant, tool, system</li><li><code>content</code>: The message content</li><li><code>metadata</code>: Tool call IDs, timestamps, branch info</li></ul><p>This format is append-only — branching just means adding new entries with different <code>parentId</code> values pointing to existing messages. The active branch is tracked by following the chain of most recent <code>parentId</code> references.</p><h2 id="context-management-compared-to-other-agents" tabindex="-1">Context Management Compared to Other Agents <a class="header-anchor" href="#context-management-compared-to-other-agents" aria-label="Permalink to &quot;Context Management Compared to Other Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Claude Code</th><th>Aider</th><th>Goose</th><th>Pi</th></tr></thead><tbody><tr><td>Project instructions</td><td>CLAUDE.md</td><td>.aider.conf.yml</td><td>profiles</td><td>AGENTS.md</td></tr><tr><td>System prompt control</td><td>No</td><td>Limited</td><td>No</td><td>Full (SYSTEM.md)</td></tr><tr><td>Progressive disclosure</td><td>No</td><td>No</td><td>No</td><td>Yes (Skills)</td></tr><tr><td>Compaction</td><td>Auto</td><td>Auto</td><td>Auto</td><td>Auto + customizable</td></tr><tr><td>Session branching</td><td>No</td><td>No</td><td>No</td><td>Yes (tree-structured)</td></tr><tr><td>Cross-provider handoff</td><td>No</td><td>No</td><td>No</td><td>Yes (pi-ai)</td></tr><tr><td>Dynamic context injection</td><td>Limited</td><td>No</td><td>Extensions</td><td>Extensions</td></tr><tr><td>Prompt templates</td><td>No</td><td>No</td><td>No</td><td>Yes (/name)</td></tr></tbody></table><p>Pi&#39;s context management is arguably the most flexible of any terminal coding agent, not because it does the most by default, but because every layer is customizable and extensible.</p>`,37))])}const C=n(p,[["render",h]]);export{v as __pageData,C as default};
